# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
from umqtt.simple import MQTTClient

# MQTT Broker configuration
BROKER_IP = "192.168.1.100"
CLIENT_ID = "sensor_001"
MQTT_TOPIC = "sensors/temp"

# Initialize ADC for temperature sensor
adc = machine.ADC(machine.Pin(34))
adc.atten(machine.ADC.ATTN_11DB)

# Initialize MQTT client
client = MQTTClient(CLIENT_ID, BROKER_IP)

def read_temperature():
    # Read ADC value and convert to temperature
    adc_value = adc.read()
    voltage = adc_value * 3.3 / 4095
    temperature = (voltage - 0.5) * 100
    return temperature

def publish_sensor_data():
    try:
        # Connect to MQTT broker
        client.connect()
        
        # Read temperature
        temp = read_temperature()
        
        # Publish to MQTT topic
        client.publish(MQTT_TOPIC, str(temp))
        
        # Disconnect
        client.disconnect()
        
        print("Temperature published:", temp)
        
    except Exception as e:
        print("MQTT publish error:", e)

# Main loop
while True:
    publish_sensor_data()
    time.sleep(10)